Here's the code for a FlatList component with infinite scroll pagination that fetches 20 items per page from an API using React Native, Expo, and TypeScript:

```jsx
import React, { useEffect, useState } from 'react';
import { FlatList, ActivityIndicator, Text } from 'react-native';
import axios from 'axios';

type Item = {
  id: number;
  title: string;
};

interface Props {}

const InfiniteScrollFlatList: React.FC<Props> = () => {
  const [data, setData] = useState<Item[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const response = await axios.get(`https://api.example.com/items?page=${page}`);
      const newData = [...data, ...response.data];
      setData(newData);
      if (response.data.length < 20) {
        setHasMore(false);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLoadMore = () => {
    if (!hasMore) return;
    setPage((prevPage) => prevPage + 1);
    fetchData();
  };

  return (
    <FlatList
      data={data}
      renderItem={({ item }) => <Text>{item.title}</Text>}
      keyExtractor={(item) => item.id.toString()}
      onEndReachedThreshold={0.5}
      onEndReached={handleLoadMore}
      ListFooterComponent={isLoading ? <ActivityIndicator /> : null}
    />
  );
};

export default InfiniteScrollFlatList;
