Here's the code for the `useDebounce` custom hook and a functional component using Expo and React Native:

```jsx
import { useState, useEffect } from 'react';
import { TextInput } from 'react-native';

const useDebounce = (value, delay) => {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
};

const SearchInput = ({ onSearch }) => {
  const [text, setText] = useState('');
  const debouncedText = useDebounce(text, 500);

  const handleChange = (event) => {
    setText(event.target.value);
  };

  const handleSubmit = () => {
    onSearch(debouncedText);
  };

  return (
    <View style={{ flex: 1, alignItems: 'center' }}>
      <TextInput
        style={{ height: 40, borderColor: 'gray', borderWidth: 1, paddingLeft: 10 }}
        onChange={handleChange}
        onSubmitEditing={handleSubmit}
        value={text}
        placeholder="Search"
      />
    </View>
  );
};
```

This code defines a `useDebounce` custom hook that takes a value and delay as arguments, and returns the debounced version of the value. The SearchInput component uses this hook to create a search input field with a TextInput component from React Native. When the user types in the input or submits it, the debounced text is passed to the `onSearch` callback function.

import React, { useState, useEffect } from 'react';
import { View, Text, ActivityIndicator, FlatList, Alert } from 'react-native';
