Here's the code for creating a local SQLite database using `expo-sqlite` and implementing CRUD operations for a `todos` table in React Native:

```jsx
import React, { useEffect, useState } from 'react';
import { StyleSheet, Text, View, Button, FlatList } from 'react-native';
import * as SQLite from 'expo-sqlite';

const db = SQLite.openDatabase('todos.db');

const TodoItem = ({ todo }) => (
  <View style={styles.item}>
    <Text style={styles.title}>{todo.title}</Text>
    <Button title="Delete" onPress={() => deleteTodo(todo.id)} />
  </View>
);

const App = () => {
  const [todos, setTodos] = useState([]);

  useEffect(() => {
    db.transaction((tx) => {
      tx.executeSql('CREATE TABLE IF NOT EXISTS todos (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT)', [], () => {});
    });

    listTodos();
  }, []);

  const addTodo = (title) => {
    db.transaction((tx) => {
      tx.executeSql(
        'INSERT INTO todos (title) VALUES (?)',
        [title],
        (_tx, _res) => listTodos()
      );
    });
  };

  const listTodos = () => {
    db.transaction((tx) => {
      tx.executeSql('SELECT * FROM todos', [], (_, res) => {
        const todos = [];
        for (let i = 0; i < res.rows.length; i++) {
          todos.push(res.rows.item(i));
        }
        setTodos(todos);
      });
    });
  };

  const deleteTodo = (id) => {
    db.transaction((tx) => {
      tx.executeSql(`DELETE FROM todos WHERE id=${id}`, [], () => listTodos());
    });
  };

  return (
    <View style={styles.container}>
      <Button title="Add Todo" onPress={() => addTodo('New Todo')} />
      <FlatList data={todos} renderItem={({ item }) => <TodoItem todo={item} />} keyExtractor={(item) => item.id.toString()} />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
    alignItems: 'center',
    justifyContent: 'center',
  },
  item: {
    backgroundColor: '#f9c2ff',
    padding: 20,
    marginVertical: 8,
    marginHorizontal: 16,
  },
  title: {
    fontSize: 32,
  },
});

export default App;
```

