Here is a simple implementation of a theme switcher using React Native, Expo, TypeScript, and the `@react-navigation/native` library for navigation:

```tsx
import React, { useEffect, useState } from 'react';
import { StyleSheet, Text, View, TouchableOpacity, Switch } from 'react-native';
import { useTheme, ThemeProvider } from '@react-navigation/native';
import * as AsyncStorage from 'expo-async-storage';

const THEME_KEY = 'theme';

const App = () => {
  const [isDark, setIsDark] = useState(false);

  const { colors } = useTheme();

  useEffect(() => {
    const loadTheme = async () => {
      const storedTheme = await AsyncStorage.getItem(THEME_KEY);
      if (storedTheme === 'true') {
        setIsDark(true);
      } else {
        setIsDark(false);
      }
    };

    loadTheme();
  }, []);

  const handleThemeChange = async () => {
    setIsDark(!isDark);
    await AsyncStorage.setItem(THEME_KEY, String(isDark));
  };

  return (
    <ThemeProvider value={{ dark: isDark }}>
      <View style={styles.container}>
        <Text style={styles.title}>Theme Switcher</Text>
        <Switch
          trackColor={{ false: colors.text, true: colors.background }}
          thumbColor={isDark ? colors.text : colors.background}
          ios_backgroundTrackingOpacity={0.5}
          onValueChange={handleThemeChange}
          value={isDark}
        />
      </View>
    </ThemeProvider>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  title: {
    fontSize: 24,
    marginBottom: 20,
  },
});

export default App;
```

This code creates a functional component called `App`, which uses the `useTheme` hook from `@react-navigation/native` to access the current theme and sets the state for the dark mode preference. The `handleThemeChange` function toggles the dark mode preference and saves it in AsyncStorage.

The component renders a simple view with a title, a switch for toggling the theme, and uses the provided theme from the `useTheme` hook to style the components.

